import{_ as s,o as n,c as e,ai as t}from"./chunks/framework.CgfAAQZ5.js";const u=JSON.parse('{"title":"Embedding 矩阵 与 多头注意力","description":"","frontmatter":{},"headers":[],"relativePath":"ai-learning-notes/embedding-and-multihead.md","filePath":"ai-learning-notes/embedding-and-multihead.md","lastUpdated":1779095553000}'),p={name:"ai-learning-notes/embedding-and-multihead.md"};function l(i,a,o,d,c,r){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="embedding-矩阵-与-多头注意力" tabindex="-1">Embedding 矩阵 与 多头注意力 <a class="header-anchor" href="#embedding-矩阵-与-多头注意力" aria-label="Permalink to &quot;Embedding 矩阵 与 多头注意力&quot;">​</a></h1><blockquote><p>记录于 2026-05-18，对话整理</p></blockquote><hr><h2 id="一个词是怎么变成数字的" tabindex="-1">一个词是怎么变成数字的 <a class="header-anchor" href="#一个词是怎么变成数字的" aria-label="Permalink to &quot;一个词是怎么变成数字的&quot;">​</a></h2><p>每个词先通过<strong>分词器</strong>转为 ID，再查 <strong>Embedding 矩阵</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;猫&quot;  →  ID: 2347  →  查 Embedding 矩阵第 2347 行</span></span>
<span class="line"><span>                              ↓</span></span>
<span class="line"><span>                    [0.23, -0.81, 0.54, ..., 0.12]   ← 512 个数</span></span></code></pre></div><p>这 512 个数就代表了&quot;猫&quot;这个词在语义空间里的坐标。</p><h3 id="训练前-vs-训练后" tabindex="-1">训练前 vs 训练后 <a class="header-anchor" href="#训练前-vs-训练后" aria-label="Permalink to &quot;训练前 vs 训练后&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>Embedding 里的数</th></tr></thead><tbody><tr><td>训练前</td><td>随机初始化</td></tr><tr><td>训练后</td><td>语义相近的词自动靠近</td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>训练后的向量空间：</span></span>
<span class="line"><span>  &quot;猫&quot;  ●</span></span>
<span class="line"><span>  &quot;狗&quot;  ●   ← 距离近，语义相似</span></span>
<span class="line"><span>  &quot;汽车&quot;      ●   ← 距离远</span></span>
<span class="line"><span>  &quot;飞机&quot;      ●</span></span></code></pre></div><h3 id="为什么是-512-维" tabindex="-1">为什么是 512 维？ <a class="header-anchor" href="#为什么是-512-维" aria-label="Permalink to &quot;为什么是 512 维？&quot;">​</a></h3><p>512 是 Transformer 原始论文里定的超参数（<code>d_model = 512</code>）。维数越高，能表达的语义越丰富，但计算量也越大。不是固定的，GPT-3 用了 12288 维。</p><hr><h2 id="多头注意力-为什么要-多头" tabindex="-1">多头注意力：为什么要&quot;多头&quot; <a class="header-anchor" href="#多头注意力-为什么要-多头" aria-label="Permalink to &quot;多头注意力：为什么要&quot;多头&quot;&quot;">​</a></h2><h3 id="单头-vs-多头" tabindex="-1">单头 vs 多头 <a class="header-anchor" href="#单头-vs-多头" aria-label="Permalink to &quot;单头 vs 多头&quot;">​</a></h3><p>单头注意力只有一种&quot;视角&quot;——每次只从一个角度看词与词之间的关系。</p><p>多头注意力把 512 维分成多个子空间，每个头负责一种关注模式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>512 维 ÷ 8 头 = 每头 64 维</span></span>
<span class="line"><span></span></span>
<span class="line"><span>头 1：[0..63]    关注主谓关系（&quot;猫&quot; 和 &quot;跑&quot;）</span></span>
<span class="line"><span>头 2：[64..127]  关注修饰关系（&quot;快速&quot; 修饰 &quot;跑&quot;）</span></span>
<span class="line"><span>头 3：[128..191] 关注指代关系（&quot;它&quot; 指代 &quot;猫&quot;）</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>头 8：[448..511] 关注位置/顺序信息</span></span></code></pre></div><h3 id="头数是固定的吗" tabindex="-1">头数是固定的吗？ <a class="header-anchor" href="#头数是固定的吗" aria-label="Permalink to &quot;头数是固定的吗？&quot;">​</a></h3><p><strong>不固定</strong>，由 <code>d_model ÷ d_head</code> 决定：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>d_model = 512，每头 64 维  →  8 头</span></span>
<span class="line"><span>d_model = 768，每头 64 维  →  12 头（BERT-base）</span></span>
<span class="line"><span>d_model = 1024，每头 64 维 →  16 头（BERT-large）</span></span></code></pre></div><p>叫&quot;多头&quot;而不是&quot;8头&quot;，就是因为头数不固定。</p><h3 id="子空间是什么意思" tabindex="-1">子空间是什么意思 <a class="header-anchor" href="#子空间是什么意思" aria-label="Permalink to &quot;子空间是什么意思&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>完整向量（512维）= 多个子空间的拼接</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[  头1的64维  |  头2的64维  | ... |  头8的64维  ]</span></span>
<span class="line"><span>  &quot;看主谓&quot;      &quot;看修饰&quot;              &quot;看位置&quot;</span></span></code></pre></div><p>每个头在自己的 64 维子空间里独立计算注意力，最后把结果拼回来。这样模型能同时从多个角度理解词和词的关系。</p><hr><h2 id="整体流程回顾" tabindex="-1">整体流程回顾 <a class="header-anchor" href="#整体流程回顾" aria-label="Permalink to &quot;整体流程回顾&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;猫 快速 跑&quot;</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼ Embedding（查表）</span></span>
<span class="line"><span>[512维] [512维] [512维]</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼ 多头注意力（分成8个子空间并行计算）</span></span>
<span class="line"><span>每头各算：这个词该关注哪些词？</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼ 拼回 512 维</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼ 前馈网络</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼ 下一层...（共 6~96 层）</span></span></code></pre></div>`,28)])])}const b=s(p,[["render",l]]);export{u as __pageData,b as default};
